package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	osexec "os/exec"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
)

// NowFunc allows tests to override time.Now for deterministic PreserveRef output.
var NowFunc = time.Now

// PreserveRef builds the documented hidden ref for a preserved iteration.
func PreserveRef(beadID, baseRev string) string {
	shortSHA := baseRev
	if len(shortSHA) > 12 {
		shortSHA = shortSHA[:12]
	}
	timestamp := NowFunc().UTC().Format("20060102T150405Z")
	return fmt.Sprintf("refs/ddx/iterations/%s/%s-%s", beadID, timestamp, shortSHA)
}

// GateCheckResult records the outcome of one required execution gate.
type GateCheckResult struct {
	DefinitionID string `json:"definition_id"`
	Required     bool   `json:"required"`
	ExitCode     int    `json:"exit_code"`
	// Status is "pass", "fail", or "skipped".
	Status string `json:"status"`
	Stdout string `json:"stdout,omitempty"`
	Stderr string `json:"stderr,omitempty"`
	// Ratchet captures the ratchet evaluation when the gate declared
	// thresholds. Populated for both pass and fail decisions so HELIX can
	// distinguish ratchet outcomes from generic command failures.
	Ratchet *RatchetEvidence `json:"ratchet,omitempty"`
}

// RatchetEvidence is the machine-readable record of one ratchet evaluation
// performed before landing. Threshold/Observed carry the authored ratchet
// and the observed value; Decision is "pass" or "fail"; Reason provides a
// short explanation of what was compared ("observed 310 ms > ratchet 250 ms").
type RatchetEvidence struct {
	DefinitionID string  `json:"definition_id"`
	MetricID     string  `json:"metric_id,omitempty"`
	Comparison   string  `json:"comparison,omitempty"`
	Threshold    float64 `json:"threshold"`
	Observed     float64 `json:"observed"`
	Unit         string  `json:"unit,omitempty"`
	Decision     string  `json:"decision"`
	Reason       string  `json:"reason,omitempty"`
}

// RatchetPreserveReason marks a landing that was preserved because a declared
// ratchet was not met. Callers match on this exact string (via the landing
// result's Reason field) to bucket ratchet-preserved attempts apart from
// generic gate failures.
const RatchetPreserveReason = "ratchet miss"

// executeBeadChecks is the machine-readable schema for checks.json.
// Written by the orchestrator when gate evaluation runs.
type executeBeadChecks struct {
	AttemptID       string            `json:"attempt_id"`
	EvaluatedAt     time.Time         `json:"evaluated_at"`
	Summary         string            `json:"summary"`
	Results         []GateCheckResult `json:"results"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
}

// OrchestratorGitOps abstracts the git operations needed by the parent-side
// orchestrator for preserving worker results under iteration refs.
//
// NOTE: The Merge(dir, rev) method that existed here before the land
// coordinator redesign has been DELETED. All target-branch writes now flow
// through Land() in execute_bead_land.go and its per-project serialized
// coordinator. See ddx-8746d8a6 / ddx-e14efc58 / ddx-6aa50e57 for the
// rationale: the old path produced "chore: checkpoint before merge" noise
// and workers racing on the same projectRoot could corrupt each other's
// intermediate state. Land() serializes through a single goroutine and
// uses `git merge --no-ff` when the target has advanced, so the worker's
// commit is never rewritten and replay sees the same inputs it originally saw.
//
// The LandingAdvancer field on BeadLandingOptions is the coordinator
// injection point for LandBeadResult callers that need to ff the target
// branch. When LandingAdvancer is nil (the interactive single-bead CLI),
// LandBeadResult falls back to preserving the result under
// refs/ddx/iterations/<bead-id>/... rather than modifying the target branch.
type OrchestratorGitOps interface {
	UpdateRef(dir, ref, sha string) error
}

// BeadLandingOptions controls how the orchestrator lands a completed worker result.
type BeadLandingOptions struct {
	// NoMerge skips the land step and preserves the result under
	// refs/ddx/iterations/<bead-id>/... instead.
	NoMerge bool

	// WtPath is the path to a worktree checked out at ResultRev, used for gate
	// evaluation. When empty, gate evaluation is skipped (the worktree has
	// typically been cleaned up by the time the orchestrator runs).
	WtPath string

	// GovernIDs are the governing artifact IDs to use for gate evaluation.
	// Only used when WtPath is non-empty. Typically extracted from the worker's
	// manifest artifact via ExtractGoverningIDsFromManifest.
	GovernIDs []string

	// ChecksArtifactPath is the absolute path to write checks.json. Optional.
	ChecksArtifactPath string
	// ChecksArtifactRel is the relative path stored in the result for checks.json.
	ChecksArtifactRel string

	// LandingAdvancer, when non-nil, replaces the old in-process Merge step
	// with the coordinator-pattern Land() call. The callback is expected to
	// run the local land sequence serialized against other submissions for
	// the same projectRoot. When nil, LandBeadResult falls back to
	// preserving the result under refs/ddx/iterations/<bead-id>/...
	// rather than touching the target branch.
	LandingAdvancer func(res *ExecuteBeadResult) (*LandResult, error)
}

// BeadLandingResult records the outcome of the orchestrator's landing step.
type BeadLandingResult struct {
	// Outcome is one of: "merged", "preserved", "no-changes".
	Outcome string `json:"outcome"`
	// Reason is a human-readable explanation of the outcome.
	Reason string `json:"reason,omitempty"`
	// PreserveRef is set when the result was preserved under refs/ddx/iterations/...
	PreserveRef string `json:"preserve_ref,omitempty"`
	// GateResults holds the outcome of each required execution gate.
	GateResults []GateCheckResult `json:"gate_results,omitempty"`
	// RequiredExecSummary is "pass", "fail", or "skipped".
	RequiredExecSummary string `json:"required_exec_summary,omitempty"`
	// ChecksFile is the relative path to checks.json when gate results were written.
	ChecksFile string `json:"checks_file,omitempty"`
	// RatchetEvidence aggregates every ratchet-evaluated gate's evidence for
	// the attempt. Surfaced separately from GateResults so HELIX and other
	// consumers can tell apart ratchet outcomes from generic gate failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	// RatchetSummary is "pass", "fail", or "" (no ratchets evaluated).
	RatchetSummary string `json:"ratchet_summary,omitempty"`
}

// LandBeadResult is the parent-side orchestrator. It receives a completed worker
// result and decides whether to merge, preserve, or report no-changes. All
// Merge, UpdateRef, gate evaluation, and preserve-ref management live here.
// The worker (ExecuteBead) must not call any of these operations.
//
// Outcome rules:
//   - ResultRev == BaseRev → "no-changes" (agent made no commits)
//   - ExitCode != 0 with commits → "preserved" (agent failed but left output)
//   - Gate failed → "preserved"
//   - NoMerge → "preserved"
//   - Default → attempt merge; on conflict → "preserved"
func LandBeadResult(projectRoot string, res *ExecuteBeadResult, gitOps OrchestratorGitOps, opts BeadLandingOptions) (*BeadLandingResult, error) {
	landing := &BeadLandingResult{}

	// Agent failed with no commits: report as error (not no-changes).
	// Prefer res.Reason (e.g. HeadRev failure set by worker) over res.Error
	// (agent error) so the primary context failure is surfaced as the reason.
	agentFailed := res.ExitCode != 0 || res.Outcome == ExecuteBeadOutcomeTaskFailed
	if agentFailed && res.ResultRev == res.BaseRev {
		landing.Outcome = "error"
		switch {
		case res.Reason != "":
			landing.Reason = res.Reason
		case res.Error != "":
			landing.Reason = res.Error
		default:
			landing.Reason = "agent execution failed"
		}
		return landing, nil
	}

	// No changes from the worker: nothing to land.
	if res.ResultRev == res.BaseRev {
		if res.Outcome == ExecuteBeadOutcomeTaskNoEvidence || res.FailureMode == FailureModeNoEvidenceProduced {
			landing.Outcome = "no-evidence"
			if res.Reason != "" {
				landing.Reason = res.Reason
			} else if res.Error != "" {
				landing.Reason = res.Error
			} else {
				landing.Reason = "agent exited without a commit or no_changes_rationale.txt"
			}
			return landing, nil
		}
		landing.Outcome = "no-changes"
		if res.NoChangesRationale != "" {
			landing.Reason = res.NoChangesRationale
		} else {
			landing.Reason = "agent made no commits"
		}
		return landing, nil
	}

	// Integrity violation detected by the worker's structured post-agent
	// validation (ddx-725b65b4): the agent exited cleanly and left commits, but
	// the attempt rewrote its commit, left empty pre-commit gate evidence, or
	// left tracked files uncommitted. Preserve the commits for operator review
	// under an iteration ref with the integrity reason rather than letting them
	// merge as success; the specific explanation rides on res.Error.
	if res.FailureMode == FailureModeAttemptIntegrity && res.ResultRev != res.BaseRev {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = AttemptIntegrityPreserveReason
		return landing, nil
	}

	// Agent failed but produced commits: preserve without attempting merge.
	if agentFailed {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = "agent execution failed"
		return landing, nil
	}

	// Evaluate required gates when a worktree path and governing IDs are
	// provided. EvaluateRequiredGatesForResult is the canonical helper —
	// shared with upstream callers that want gate eval before submitting
	// through the coordinator. It mutates res.GateResults / RequiredExecSummary
	// / RatchetEvidence / RatchetSummary / ChecksFile in place; we mirror the
	// outputs onto landing so ApplyLandingToResult can copy them back later
	// without losing the existing landing.* contract.
	anyGateFailed, anyRatchetFailed, gateErr := EvaluateRequiredGatesForResult(
		opts.WtPath, opts.GovernIDs, res, projectRoot,
		opts.ChecksArtifactPath, opts.ChecksArtifactRel,
	)
	if gateErr != nil {
		return nil, gateErr
	}
	gateResults := res.GateResults
	landing.GateResults = gateResults
	landing.RequiredExecSummary = res.RequiredExecSummary
	landing.RatchetEvidence = res.RatchetEvidence
	landing.RatchetSummary = res.RatchetSummary
	landing.ChecksFile = res.ChecksFile

	// Gate failed: preserve instead of merging. Ratchet misses get a
	// dedicated reason so status/failure_mode classifiers can distinguish
	// them from generic command failures.
	if anyGateFailed {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		if anyRatchetFailed {
			landing.Reason = RatchetPreserveReason
		} else {
			landing.Reason = "post-run checks failed"
		}
		return landing, nil
	}

	// --no-merge: preserve unconditionally.
	if opts.NoMerge {
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
			return nil, fmt.Errorf("preserving result ref: %w", err)
		}
		landing.Outcome = "preserved"
		landing.PreserveRef = ref
		landing.Reason = "--no-merge specified"
		return landing, nil
	}

	// Default: land the worker's commits on the target branch. When a
	// LandingAdvancer is provided (server coordinator / --local coordinator)
	// it runs the local land sequence serialized per projectRoot. When no
	// advancer is provided, LandBeadResult falls back to preserving the
	// result under refs/ddx/iterations/ — the interactive single-bead CLI
	// path, which intentionally does NOT auto-advance the target branch
	// (the operator moves the ref themselves).
	if opts.LandingAdvancer != nil {
		land, landErr := opts.LandingAdvancer(res)
		if landErr != nil {
			return nil, fmt.Errorf("land advancer: %w", landErr)
		}
		switch land.Status {
		case "landed":
			landing.Outcome = "merged"
			if land.Merged {
				landing.Reason = "merged onto current tip"
			}
		case "preserved":
			landing.Outcome = "preserved"
			landing.PreserveRef = land.PreserveRef
			landing.Reason = land.Reason
		case "no-changes":
			landing.Outcome = "no-changes"
			landing.Reason = land.Reason
		default:
			landing.Outcome = "preserved"
			landing.Reason = "unknown land status: " + land.Status
		}
		return landing, nil
	}

	// No advancer: preserve under refs/ddx/iterations/ as a safe fallback.
	ref := PreserveRef(res.BeadID, res.BaseRev)
	if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
		return nil, fmt.Errorf("preserving result ref (no land advancer): %w", err)
	}
	landing.Outcome = "preserved"
	landing.PreserveRef = ref
	landing.Reason = "no land advancer configured"
	return landing, nil
}

// ApplyLandingToResult merges a BeadLandingResult's fields into an
// ExecuteBeadResult so callers can output a single unified record. It
// overwrites Outcome, Status, Detail, Reason, PreserveRef, GateResults,
// RequiredExecSummary, and ChecksFile based on the landing decision.
func ApplyLandingToResult(res *ExecuteBeadResult, landing *BeadLandingResult) {
	res.Outcome = landing.Outcome
	res.Reason = landing.Reason
	res.PreserveRef = landing.PreserveRef
	res.GateResults = landing.GateResults
	res.RequiredExecSummary = landing.RequiredExecSummary
	res.ChecksFile = landing.ChecksFile
	res.RatchetEvidence = landing.RatchetEvidence
	res.RatchetSummary = landing.RatchetSummary
	// Re-classify status based on landing outcome and reason.
	res.Status = ClassifyExecuteBeadStatus(landing.Outcome, res.ExitCode, landing.Reason)
	res.Detail = ExecuteBeadStatusDetail(res.Status, landing.Reason, res.Error)
	// Refine failure_mode with landing-level signals. A clean merge clears
	// the field; merge conflict or gate failure overrides the worker-level
	// classification; other preserved outcomes keep the worker's mode.
	res.FailureMode = classifyLandingFailureMode(landing.Outcome, landing.Reason, landing.GateResults, res.FailureMode)
	res.OrchestratorStatus = res.Status
}

// ExtractGoverningIDsFromManifest reads governing artifact IDs from a manifest
// JSON file at manifestAbs (absolute path). Returns nil when the file cannot
// be read. Callers use this to populate BeadLandingOptions.GovernIDs.
func ExtractGoverningIDsFromManifest(manifestAbs string) []string {
	if manifestAbs == "" {
		return nil
	}
	type manifestShape struct {
		Governing []struct {
			ID string `json:"id"`
		} `json:"governing"`
	}
	raw, err := os.ReadFile(manifestAbs)
	if err != nil {
		return nil
	}
	var m manifestShape
	if err := json.Unmarshal(raw, &m); err != nil {
		return nil
	}
	ids := make([]string, 0, len(m.Governing))
	for _, g := range m.Governing {
		if g.ID != "" {
			ids = append(ids, g.ID)
		}
	}
	return ids
}

// RecoverOrphans removes orphaned execute-bead worktrees for a given bead ID.
// This is a belt-and-suspenders sweep for crashed or otherwise unreached
// attempts; the worker now performs the normal post-attempt cleanup on its
// own before the next spawn.
func RecoverOrphans(gitOps GitOps, workDir, beadID string) {
	paths, err := gitOps.WorktreeList(workDir)
	if err != nil {
		return
	}
	// Match by basename prefix so orphans are found regardless of their parent
	// directory (legacy .ddx/ vs new $TMPDIR/ddx-exec-wt/).
	basenamePrefix := ExecuteBeadWtPrefix + beadID + "-"
	orphanRemoved := false
	for _, p := range paths {
		if strings.HasPrefix(filepath.Base(p), basenamePrefix) {
			_ = gitOps.WorktreeRemove(workDir, p)
			orphanRemoved = true
		}
	}
	_ = gitOps.WorktreePrune(workDir)

	// Sweep stale run-state left by crashed workers. Per-attempt records are
	// cleared individually so concurrent attempts for other beads remain visible.
	if states, _ := ReadRunStates(workDir); len(states) > 0 {
		for _, state := range states {
			remove := orphanRemoved && state.BeadID == beadID
			if !remove && state.BeadID == beadID {
				remove = true
			}
			if !remove && state.WorktreePath != "" {
				if _, err := os.Stat(state.WorktreePath); os.IsNotExist(err) {
					remove = true
				}
			}
			if remove {
				_ = ClearRunStateAttempt(workDir, state.AttemptID)
			}
		}
	}
}

// evaluateRequiredGates resolves graph-authored execution documents that are
// required and linked to any of the governing artifact IDs, then runs each
// one. When a gate declares a ratchet threshold, the command's numeric output
// is compared against the threshold after a successful exit; a ratchet miss
// demotes the gate status to "fail" and records the evidence the orchestrator
// surfaces as part of its landing decision.
//
// Returns: gate results (one per candidate), anyFailed (true if any gate's
// final status is "fail"), anyRatchetFailed (true if any failure was caused
// by a ratchet miss rather than a non-zero exit), and any fatal error from
// walking the graph (soft errors are swallowed).
func evaluateRequiredGates(wtPath string, governingIDs []string) ([]GateCheckResult, bool, bool, error) {
	if len(governingIDs) == 0 {
		return nil, false, false, nil
	}

	graph, err := docgraph.BuildGraphWithConfig(wtPath)
	if err != nil {
		// Soft error: skip gate evaluation rather than blocking all landings.
		return nil, false, false, nil
	}

	governingSet := make(map[string]bool, len(governingIDs))
	for _, id := range governingIDs {
		governingSet[id] = true
	}

	type execCandidate struct {
		id         string
		command    []string
		cwd        string
		comparison string
		thresholds *docgraph.DocThresholds
		metric     *docgraph.DocMetricSpec
	}
	var candidates []execCandidate
	for _, doc := range graph.Documents {
		if doc.ExecDef == nil || !doc.ExecDef.Required {
			continue
		}
		ed := doc.ExecDef
		if ed.Kind != "command" {
			continue
		}
		if len(ed.Command) == 0 {
			continue
		}
		linked := false
		for _, dep := range doc.DependsOn {
			if governingSet[dep] {
				linked = true
				break
			}
		}
		if !linked {
			for _, artID := range ed.ArtifactIDs {
				if governingSet[artID] {
					linked = true
					break
				}
			}
		}
		if !linked {
			continue
		}
		candidates = append(candidates, execCandidate{
			id:         doc.ID,
			command:    ed.Command,
			cwd:        ed.Cwd,
			comparison: ed.Comparison,
			thresholds: ed.Thresholds,
			metric:     ed.Metric,
		})
	}

	if len(candidates) == 0 {
		return nil, false, false, nil
	}

	anyFailed := false
	anyRatchetFailed := false
	results := make([]GateCheckResult, 0, len(candidates))
	for _, c := range candidates {
		cwd := wtPath
		if c.cwd != "" {
			if filepath.IsAbs(c.cwd) {
				cwd = c.cwd
			} else {
				cwd = filepath.Join(wtPath, c.cwd)
			}
		}

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
		cmd := osexec.CommandContext(ctx, c.command[0], c.command[1:]...)
		cmd.Dir = cwd
		var stdoutBuf, stderrBuf strings.Builder
		cmd.Stdout = &stdoutBuf
		cmd.Stderr = &stderrBuf
		runErr := cmd.Run()
		cancel()

		stdoutStr := strings.TrimSpace(stdoutBuf.String())
		stderrStr := strings.TrimSpace(stderrBuf.String())
		gr := GateCheckResult{
			DefinitionID: c.id,
			Required:     true,
			Stdout:       stdoutStr,
			Stderr:       stderrStr,
		}
		if runErr != nil {
			gr.ExitCode = 1
			if exitErr, ok := runErr.(*osexec.ExitError); ok {
				gr.ExitCode = exitErr.ExitCode()
			}
			gr.Status = "fail"
			anyFailed = true
		} else {
			gr.Status = "pass"
		}

		// Apply ratchet evaluation when thresholds are declared. Only runs
		// when the command exited cleanly — a non-zero exit already failed
		// the gate and there's no point parsing unreliable output.
		if c.thresholds != nil && gr.Status == "pass" {
			evidence := evaluateRatchet(c.id, c.comparison, c.thresholds, c.metric, stdoutStr, stderrStr)
			gr.Ratchet = evidence
			if evidence.Decision == "fail" {
				gr.Status = "fail"
				anyFailed = true
				anyRatchetFailed = true
			}
		}
		results = append(results, gr)
	}

	return results, anyFailed, anyRatchetFailed, nil
}

// evaluateRatchet parses the gate's observed value from stdout and compares it
// against the declared ratchet threshold. Always returns a non-nil evidence
// record so pass/fail results both carry machine-readable provenance.
func evaluateRatchet(definitionID, comparison string, thresholds *docgraph.DocThresholds, metric *docgraph.DocMetricSpec, stdout, stderr string) *RatchetEvidence {
	if comparison == "" {
		comparison = "lower-is-better"
	}
	unit := ""
	metricID := ""
	if metric != nil {
		unit = metric.Unit
		metricID = metric.MetricID
	}
	if unit == "" {
		unit = thresholds.Unit
	}
	observed, parsedUnit, parsed := parseGateValue(stdout)
	if !parsed {
		// Fall back to stderr for tools that report numbers there.
		observed, parsedUnit, parsed = parseGateValue(stderr)
	}
	if unit == "" {
		unit = parsedUnit
	}
	evidence := &RatchetEvidence{
		DefinitionID: definitionID,
		MetricID:     metricID,
		Comparison:   comparison,
		Threshold:    thresholds.Ratchet,
		Observed:     observed,
		Unit:         unit,
	}
	if !parsed {
		evidence.Decision = "fail"
		evidence.Reason = "gate did not emit a parseable numeric value"
		return evidence
	}
	passed := ratchetPasses(comparison, thresholds.Ratchet, observed)
	if passed {
		evidence.Decision = "pass"
		evidence.Reason = formatRatchetReason(comparison, thresholds.Ratchet, observed, unit, true)
	} else {
		evidence.Decision = "fail"
		evidence.Reason = formatRatchetReason(comparison, thresholds.Ratchet, observed, unit, false)
	}
	return evidence
}

// ratchetPasses returns true when observed satisfies the ratchet constraint.
// lower-is-better: observed must be <= threshold. higher-is-better: observed
// must be >= threshold. Any other comparison string defaults to lower-is-better.
func ratchetPasses(comparison string, threshold, observed float64) bool {
	if comparison == "higher-is-better" {
		return observed >= threshold
	}
	return observed <= threshold
}

func formatRatchetReason(comparison string, threshold, observed float64, unit string, passed bool) string {
	cmpOp := "<="
	if comparison == "higher-is-better" {
		cmpOp = ">="
	}
	state := "pass"
	if !passed {
		state = "fail"
		// flip operator for failures so the message reads like "observed 310 > ratchet 250"
		if comparison == "higher-is-better" {
			cmpOp = "<"
		} else {
			cmpOp = ">"
		}
	}
	if unit != "" {
		return fmt.Sprintf("%s: observed %g %s %s ratchet %g %s", state, observed, unit, cmpOp, threshold, unit)
	}
	return fmt.Sprintf("%s: observed %g %s ratchet %g", state, observed, cmpOp, threshold)
}

// parseGateValue extracts a numeric observation from gate output. Accepts
// either a JSON object with a "value" (and optional "unit") field, or a
// trailing number with an optional unit suffix. Returns the value, the parsed
// unit (may be ""), and whether parsing succeeded.
func parseGateValue(text string) (float64, string, bool) {
	text = strings.TrimSpace(text)
	if text == "" {
		return 0, "", false
	}
	if v, u, ok := parseGateJSON(text); ok {
		return v, u, true
	}
	return parseGateText(text)
}

var gateMeasurementPattern = regexp.MustCompile(`(-?\d+(?:\.\d+)?)(?:\s*)([a-zA-Z%/]+)?`)

func parseGateJSON(text string) (float64, string, bool) {
	var obj map[string]any
	if err := json.Unmarshal([]byte(text), &obj); err != nil {
		return 0, "", false
	}
	raw, ok := obj["value"]
	if !ok {
		return 0, "", false
	}
	unit, _ := obj["unit"].(string)
	switch v := raw.(type) {
	case float64:
		return v, unit, true
	case string:
		if parsed, err := strconv.ParseFloat(v, 64); err == nil {
			return parsed, unit, true
		}
	}
	return 0, "", false
}

func parseGateText(text string) (float64, string, bool) {
	// Take the last matching measurement so "result: 310 ms" still parses.
	matches := gateMeasurementPattern.FindAllStringSubmatch(text, -1)
	if len(matches) == 0 {
		return 0, "", false
	}
	m := matches[len(matches)-1]
	v, err := strconv.ParseFloat(m[1], 64)
	if err != nil {
		return 0, "", false
	}
	unit := ""
	if len(m) >= 3 {
		unit = strings.TrimSpace(m[2])
	}
	return v, unit, true
}

// collectRatchetEvidence flattens the ratchet evidence from each gate result
// into a single slice the orchestrator stores on the landing record.
func collectRatchetEvidence(gateResults []GateCheckResult) []RatchetEvidence {
	var out []RatchetEvidence
	for _, gr := range gateResults {
		if gr.Ratchet != nil {
			out = append(out, *gr.Ratchet)
		}
	}
	return out
}

// summarizeRatchets returns "pass", "fail", or "" (no ratchets evaluated).
func summarizeRatchets(evidence []RatchetEvidence) string {
	if len(evidence) == 0 {
		return ""
	}
	for _, e := range evidence {
		if e.Decision == "fail" {
			return "fail"
		}
	}
	return "pass"
}

// summarizeGates returns the RequiredExecSummary string for the landing result.
func summarizeGates(results []GateCheckResult, anyFailed bool) string {
	if len(results) == 0 {
		return "skipped"
	}
	if anyFailed {
		return "fail"
	}
	return "pass"
}

// Package failclass implements the FEAT-004 failure-classification routing
// policy applied by ddx work between bead-execution attempts (bead
// ddx-d27a1895).
//
// It provides four things the queue drain composes:
//
//   - Classify maps a single attempt Outcome to exactly one routing Action,
//     applying the normative failure-classification table.
//   - Escalate owns the single one-hop middle->max tier escalation, which only
//     a typed genuine failure triggers.
//   - Pool enforces a per-pool in-flight max-attempt cap that prevents a
//     multi-worker stampede when many workers fail concurrently.
//   - Pool also carries the global (per-pool, not per-bead) cooldown applied on
//     quota exhaustion.
//
// The classification table is normative; it is inlined here from the bead body
// because the upstream FEAT-004 routing addendum lives in the fizeau repo and
// is not reachable from a cold ddx agent.
package failclass

import (
	"sync"
	"time"
)

// Outcome is the typed result of a single ddx-work attempt. Every Outcome maps
// to exactly one Action via Classify.
type Outcome string

const (
	// OutcomeSuccess: the attempt satisfied the bead's acceptance criteria.
	OutcomeSuccess Outcome = "success"
	// OutcomeAlreadySatisfied: the bead was already satisfied before work.
	OutcomeAlreadySatisfied Outcome = "already_satisfied"
	// OutcomeNoChanges: the agent produced nothing and wrote a rationale.
	OutcomeNoChanges Outcome = "no_changes"
	// OutcomeGenuineFailure: tests fail after real work; acceptance unmet.
	// This is the only outcome that can trigger a tier escalation.
	OutcomeGenuineFailure Outcome = "genuine_failure"
	// OutcomeDirtyWorktree: dirty worktree or partial write.
	OutcomeDirtyWorktree Outcome = "dirty_worktree"
	// OutcomeTransport: provider transport failure (i/o timeout, conn refused,
	// 5xx).
	OutcomeTransport Outcome = "transport"
	// OutcomeQuota: quota exhausted (retry_after).
	OutcomeQuota Outcome = "quota"
	// OutcomeAuth: auth/config missing.
	OutcomeAuth Outcome = "auth"
	// OutcomeSetup: toolchain/setup failure.
	OutcomeSetup Outcome = "setup"
	// OutcomeTimeout: timeout / no-progress watchdog.
	OutcomeTimeout Outcome = "timeout"
	// OutcomeMergeConflict: merge/land conflict.
	OutcomeMergeConflict Outcome = "merge_conflict"
)

// Action is the single routing action selected for an Outcome.
type Action string

const (
	// ActionCloseBead: close the bead (success path).
	ActionCloseBead Action = "close_bead"
	// ActionCloseOrUnclaim: close or unclaim per the agent's rationale; never
	// escalate the tier.
	ActionCloseOrUnclaim Action = "close_or_unclaim"
	// ActionEscalateTier: escalate the tier exactly once (middle->max).
	ActionEscalateTier Action = "escalate_tier"
	// ActionResetRetrySameTier: clean/reset the worktree and retry at the same
	// tier (not an escalation).
	ActionResetRetrySameTier Action = "reset_retry_same_tier"
	// ActionRerouteSameTier: reroute to another dispatchable candidate at the
	// same tier; no tier change.
	ActionRerouteSameTier Action = "reroute_same_tier"
	// ActionGlobalCooldown: put the whole pool to sleep until quota reset; not
	// a per-bead mutation, not an escalation.
	ActionGlobalCooldown Action = "global_cooldown"
	// ActionOperatorAttention: explicit bead state transition to the operator
	// lane (not a notification or an indefinite wait).
	ActionOperatorAttention Action = "operator_attention"
	// ActionUnclaimRetryLater: unclaim and retry later; not an escalation.
	ActionUnclaimRetryLater Action = "unclaim_retry_later"
)

// Escalates reports whether the Action mutates the tier. Only
// ActionEscalateTier escalates; this is the single guard the escalation owner
// (ddx work) checks before calling Escalate.
func (a Action) Escalates() bool {
	return a == ActionEscalateTier
}

// ClassifyContext carries the routing state needed to resolve the tier- and
// attempt-conditional rows of the table (genuine failure and timeout).
type ClassifyContext struct {
	// AtMaxTier reports whether the attempt already ran at the maximum tier. A
	// genuine failure at the max tier goes to the operator lane instead of
	// escalating.
	AtMaxTier bool
	// SameTierRetried reports whether a same-tier retry was already consumed. A
	// second timeout (after one same-tier retry) goes to the operator lane.
	SameTierRetried bool
}

// Classify maps a single attempt Outcome to exactly one Action, applying the
// normative failure-classification table.
//
// Only OutcomeGenuineFailure can produce ActionEscalateTier, and only when the
// attempt was not already at the max tier. The no_changes, dirty, transport,
// quota, auth, setup, timeout, and merge-conflict outcomes never escalate.
func Classify(outcome Outcome, ctx ClassifyContext) Action {
	switch outcome {
	case OutcomeSuccess, OutcomeAlreadySatisfied:
		return ActionCloseBead
	case OutcomeNoChanges:
		return ActionCloseOrUnclaim
	case OutcomeGenuineFailure:
		// Single one-hop middle->max escalation; a max-tier genuine failure
		// stops escalating and goes to the operator lane.
		if ctx.AtMaxTier {
			return ActionOperatorAttention
		}
		return ActionEscalateTier
	case OutcomeDirtyWorktree:
		return ActionResetRetrySameTier
	case OutcomeTransport:
		return ActionRerouteSameTier
	case OutcomeQuota:
		return ActionGlobalCooldown
	case OutcomeAuth, OutcomeSetup:
		return ActionOperatorAttention
	case OutcomeTimeout:
		// Clean + same-tier retry once, then operator-attention.
		if ctx.SameTierRetried {
			return ActionOperatorAttention
		}
		return ActionResetRetrySameTier
	case OutcomeMergeConflict:
		return ActionUnclaimRetryLater
	default:
		// Unknown outcomes go to the operator lane rather than silently
		// escalating or retrying.
		return ActionOperatorAttention
	}
}

// Tier is a routing capability tier. Escalation is a single one-hop edge from
// TierMiddle to TierMax; no other edge escalates.
type Tier int

const (
	// TierLow is the cheapest tier and is never an escalation target.
	TierLow Tier = iota
	// TierMiddle is the default starting tier for dispatch.
	TierMiddle
	// TierMax is the strongest tier and the only escalation target.
	TierMax
)

// Escalate performs the single one-hop middle->max escalation and reports
// whether it changed the tier. Escalation is idempotent: only TierMiddle
// escalates (to TierMax); every other tier — including a tier already at
// TierMax — is returned unchanged with escalated=false. This enforces "exactly
// one middle->max" per dispatch chain.
func Escalate(t Tier) (next Tier, escalated bool) {
	if t == TierMiddle {
		return TierMax, true
	}
	return t, false
}

// Pool tracks per-pool in-flight attempts and the global cooldown for a single
// dispatch pool. It is safe for concurrent use by multiple workers.
//
// The in-flight cap prevents a multi-worker stampede: when many workers fail
// concurrently against the same pool, at most maxInFlight attempts may hold a
// slot at once. The cooldown is global to the pool (applied on quota
// exhaustion), not a per-bead mutation.
type Pool struct {
	mu            sync.Mutex
	name          string
	maxInFlight   int
	inFlight      int
	cooldownUntil time.Time
	now           func() time.Time
}

// NewPool returns a Pool with the given name and in-flight cap. A non-positive
// maxInFlight is clamped to 1. The clock defaults to time.Now and can be
// overridden for tests via SetClock.
func NewPool(name string, maxInFlight int) *Pool {
	if maxInFlight < 1 {
		maxInFlight = 1
	}
	return &Pool{
		name:        name,
		maxInFlight: maxInFlight,
		now:         time.Now,
	}
}

// SetClock overrides the pool's time source. It exists so tests can advance
// time without sleeping; the bead requires bounded, non-hanging tests.
func (p *Pool) SetClock(now func() time.Time) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.now = now
}

// Name returns the pool's name.
func (p *Pool) Name() string {
	return p.name
}

// Acquire attempts to take one in-flight slot. It returns false when the pool
// is in cooldown or the in-flight cap is already reached; otherwise it takes a
// slot and returns true. Every successful Acquire must be paired with a
// Release.
func (p *Pool) Acquire() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.now().Before(p.cooldownUntil) {
		return false
	}
	if p.inFlight >= p.maxInFlight {
		return false
	}
	p.inFlight++
	return true
}

// Release returns one in-flight slot. It never drops below zero.
func (p *Pool) Release() {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight > 0 {
		p.inFlight--
	}
}

// InFlight returns the current number of held in-flight slots.
func (p *Pool) InFlight() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight
}

// EnterCooldown applies a global pool cooldown of duration d (typically the
// quota retry_after). It is global to the pool, not a per-bead mutation:
// subsequent Acquire calls fail until the cooldown elapses. A later, longer
// cooldown extends the window; a shorter one never shortens an active window.
func (p *Pool) EnterCooldown(d time.Duration) {
	p.mu.Lock()
	defer p.mu.Unlock()
	until := p.now().Add(d)
	if until.After(p.cooldownUntil) {
		p.cooldownUntil = until
	}
}

// InCooldown reports whether the pool is currently in a global cooldown.
func (p *Pool) InCooldown() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.now().Before(p.cooldownUntil)
}

package agent

// execute_bead_land.go — the land coordinator pattern.
//
// This file implements the human-PR landing model for execute-bead results.
// The old Merge() path in execute_bead_orchestrator.go has been deleted; all
// target-ref writes now flow through Land(), which is called exactly once per
// submission by a per-project coordinator goroutine (see
// internal/server/workers.go:LandCoordinator).
//
// The flow mirrors how a human merges PRs:
//
//   1. Read the current target tip from the local branch.
//   2. If the current tip equals the worker's BaseRev — fast-forward the
//      target branch directly to the worker's ResultRev via update-ref. The
//      worker's commit keeps its original parent; no new commit is created.
//   3. Otherwise — the target has advanced since the worker started. Create
//      a temporary detached worktree at the current target tip, run
//      `git merge --no-ff` to introduce the worker's ResultRev, and
//      fast-forward the target branch to the resulting merge commit. The
//      worker's commit is NEVER rewritten: its parent is still BaseRev, so
//      a later replay observes the same inputs the worker saw.
//   4. If the merge conflicts — abort cleanly, preserve the original
//      ResultRev under refs/ddx/iterations/<bead-id>/<attempt-id>-<short-tip>,
//      and return preserved status. Target branch is never modified.
//   5. If evidence needs to be folded in, stage and commit it locally, then
//      sync the operator checkout to the new head when safe to do so.
//
// Network sync is intentionally out of scope for Land(): no fetch and no
// push happen here. Operators sync origin with raw git commands after the
// drain session completes.
//
// Replay fidelity is the reason for merge-over-rebase: a rebased commit has
// a rewritten parent that lies about what the worker saw at execution time.
// A merge commit preserves both histories — the worker's original commit
// (parent = BaseRev) and the target's prior tip — losslessly.
//
// The in-process coordinator serializes submissions inside one process. Land()
// also takes the process-shared main-git lock so separate `ddx work` processes
// Land narrows the process-shared main-git lock to the shared-ref update
// boundary so separate `ddx work` processes cannot interleave target-ref
// writes while read-only prep stays outside the lock and post-land checkout
// sync runs under the same lock acquisition.

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"go/parser"
	"go/token"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/trackerpaths"
)

const defaultLargeDeletionLineThreshold = 200

// LandRequest is one submission to the land coordinator: "here is the worker's
// result from base B to result R for bead X; land it on the project's target
// branch."
type LandRequest struct {
	// WorktreeDir is the path to the project's repository directory (the
	// directory the coordinator operates on). The original worker worktree
	// has typically already been removed by the time Land() runs — Land()
	// creates its own temporary worktrees when a merge is needed.
	WorktreeDir string

	// BaseRev is the revision the worker branched off when it started.
	// When the current target tip equals BaseRev, Land() takes the fast path.
	BaseRev string

	// ResultRev is the worker's final commit SHA. Must be reachable in the
	// project's git object store at the time Land() is called.
	ResultRev string

	// BeadID identifies the bead this submission is for. Used to build the
	// preserve-ref path on conflict.
	BeadID string

	// AttemptID uniquely identifies this land attempt. Used to build the
	// preserve-ref path on conflict so concurrent attempts for the same
	// bead do not collide.
	AttemptID string

	// TargetBranch is the branch to advance. When empty, Land() resolves
	// the project's current HEAD branch and uses that.
	TargetBranch string

	// EvidenceDir is the relative path to the per-attempt execution evidence
	// directory (e.g. ".ddx/executions/20260416T181205-b5419982"). When
	// non-empty and the main land succeeds, Land() creates a trailing
	// evidence commit that folds these files into the target branch. The
	// agent's commit SHA is NOT amended — the evidence commit is a separate
	// child commit, preserving closing_commit_sha references.
	EvidenceDir string

	// PostLandCommand is an optional project verification command run after
	// Land() advances the local target ref and syncs the worktree, but before
	// evidence commit creation or checkout sync. A failure restores the target
	// ref to its pre-land SHA and preserves ResultRev under refs/ddx/iterations.
	PostLandCommand []string

	// LargeDeletionLineThreshold overrides the default per-file deletion gate
	// threshold. Zero or negative uses defaultLargeDeletionLineThreshold.
	LargeDeletionLineThreshold int
}

// LandResult describes the outcome of a single Land() call.
type LandResult struct {
	// Status is one of:
	//   - "landed":    the target branch now points at a new commit
	//                  (either ResultRev itself on the fast-forward path,
	//                  or a merge commit on the merge path).
	//   - "preserved": the merge conflicted; ResultRev is saved under
	//                  PreserveRef and the target branch is unchanged.
	//   - "no-changes": ResultRev == BaseRev; nothing to land.
	Status string

	// NewTip is the new value of the target branch when Status == "landed".
	// On the fast-forward path NewTip == ResultRev; on the merge path NewTip
	// is the SHA of the merge commit (whose parents are the prior target
	// tip and ResultRev). Empty when preserved or no-changes.
	NewTip string

	// LandedTip is the target branch tip immediately after the implementation
	// (or already-committed evidence bundle) lands, but before any trailing
	// audit-only evidence/final-result commit. When no trailing commit is
	// created it matches NewTip.
	LandedTip string

	// TargetBranch is the resolved branch name that Land() advanced or attempted
	// to advance. It is set on landed and preserved results so callers can make
	// branch-local recovery explicit in terminal output and evidence.
	TargetBranch string

	// Merged is true when the land took the merge-commit path (current tip
	// had advanced beyond BaseRev, so Land() created a merge commit to
	// combine the worker's result with the new target tip). False on the
	// fast-forward path where the worker's commit became the new tip
	// unchanged.
	Merged bool

	// PreserveRef is set when Status == "preserved". It names the ref under
	// refs/ddx/iterations/ where ResultRev was saved for later recovery.
	PreserveRef string

	// Reason is a human-readable explanation, especially useful when
	// Status == "preserved" (e.g. "merge conflict").
	Reason string

	// MergedCommitCount is the number of commits reachable from ResultRev but
	// not from BaseRev — i.e. the "size" of the worker's contribution being
	// merged in. Zero on the no-changes path. Set on both the fast-forward
	// and merge-commit paths so metrics can compare contribution sizes.
	MergedCommitCount int

	// EvidenceCommitSHA is set when a trailing execution-evidence commit was
	// created after the main land. When set, NewTip points at this commit
	// (not at the original agent commit or merge commit).
	EvidenceCommitSHA string

	// CheckoutSyncDeferred is true when the target ref advanced but DDx left
	// the operator checkout files untouched because dirty local paths overlap
	// files changed by the new target tip.
	CheckoutSyncDeferred bool

	// CheckoutSyncDeferredPaths lists the dirty paths that caused checkout sync
	// to be skipped.
	CheckoutSyncDeferredPaths []string
}

// PreClaimResult is the outcome of a FetchOriginAncestryCheck call.
type PreClaimResult struct {
	// Action is one of:
	//   "unchanged"     — local tip == origin tip, no action taken
	//   "fast-forwarded"— local was behind origin; local branch was advanced
	//   "no-origin"     — no origin remote; check skipped
	//   "local-ahead"   — local is ahead of origin; no action needed
	//   "diverged"      — neither is ancestor of the other; claim should be aborted
	Action    string
	LocalSHA  string
	OriginSHA string
}

// IsIgnorableFetchOriginError reports whether a pre-claim ancestry-check
// failure came from the best-effort network fetch. Local worktree safety
// failures must propagate so workers do not claim work from an unsafe trunk.
func IsIgnorableFetchOriginError(err error) bool {
	if err == nil {
		return false
	}
	msg := err.Error()
	return strings.HasPrefix(msg, "git fetch origin ") || strings.HasPrefix(msg, "git fetch origin:")
}

// LandingGitOps abstracts the git operations Land() needs. RealLandingGitOps
// shells out to git; tests inject fakes or run against real temp repos.
type LandingGitOps interface {
	// CurrentBranch returns the branch HEAD currently points at in dir, or
	// an error if HEAD is detached or unresolvable.
	CurrentBranch(dir string) (string, error)

	// ResolveRef resolves ref (e.g. "refs/heads/main" or "origin/main") to a
	// commit SHA. When ref is unresolvable returns ("", error).
	ResolveRef(dir, ref string) (string, error)

	// UpdateRefTo updates ref in dir to sha. When oldSHA is non-empty, the
	// update is conditional on the current ref value equalling oldSHA.
	UpdateRefTo(dir, ref, sha, oldSHA string) error

	// SyncWorkTreeToHead syncs the index AND the working-tree files in dir
	// to HEAD after a non-checkout ref update (e.g. update-ref). fromRev is
	// the commit HEAD pointed at BEFORE the ref update; it is used to
	// compute the minimal set of tracked files changed by the update so
	// that unrelated local modifications (agent-logs, beads.jsonl heartbeat
	// writes, operator scratch) are NOT clobbered.
	//
	// Needed because Land() advances the target ref via update-ref, which
	// touches neither the index nor the worktree. Before this fix, Land()
	// only ran `git read-tree HEAD` to sync the index — leaving the main
	// worktree showing phantom deleted/modified entries for every file the
	// landed commit touched, and subsequent agents reading files from disk
	// would see stale content.
	//
	// Implementation: `git read-tree HEAD` + `git diff --name-only fromRev
	// HEAD` to enumerate changed files + `git checkout-index -f --` to
	// materialize them from the freshly-synced index.
	SyncWorkTreeToHead(dir, fromRev string) error

	// AddWorktree creates a new worktree at path checked out at rev in dir.
	AddWorktree(dir, path, rev string) error

	// AddBranchWorktree creates a new worktree at path checked out on branch
	// in dir. It is used for clean landing finalization when the operator
	// checkout already has the target branch checked out.
	AddBranchWorktree(dir, path, branch string) error

	// RemoveWorktree removes the worktree at path in dir (force).
	RemoveWorktree(dir, path string) error

	// MergeInto runs `git merge --no-ff -m msg srcRev` inside wtDir, which
	// must already be checked out at the current target tip. A clean merge
	// produces a merge commit whose parents are [currentTip, srcRev]; the
	// commit SHA can be read with HeadRevAt. Returns nil on clean merge,
	// or an error on conflict. On error, the implementation is responsible
	// for running `git merge --abort` so the worktree is left clean.
	MergeInto(wtDir, srcRev, msg string) error

	// HeadRevAt returns HEAD of the git workdir at dir.
	HeadRevAt(dir string) (string, error)

	// CountCommits returns the number of commits reachable from tip but not
	// from base (i.e. git rev-list --count base..tip). Used to record the
	// contribution size in land metrics. Returns 0 on error.
	CountCommits(dir, base, tip string) int

	// StageDir stages all files under relPath in dir for the next commit.
	StageDir(dir, relPath string) error

	// CommitStaged creates a commit from currently staged changes using msg
	// as the commit message. Returns (sha, nil) when a commit was made,
	// ("", nil) when nothing was staged, and ("", err) on failure.
	CommitStaged(dir, msg string) (string, error)

	// DiffNumstat returns the output of `git diff --numstat base tip --` in
	// dir. Used by the large-deletion gate. Returning ("", nil) indicates no
	// diffable output (e.g. in a test stub with no real repo).
	DiffNumstat(dir, base, tip string) (string, error)

	// DiffNameOnly returns the list of changed file paths between base and tip
	// in dir (`git diff --name-only base tip --`). Used by the syntax-sanity
	// gate. Returning (nil, nil) indicates no changes.
	DiffNameOnly(dir, base, tip string) ([]string, error)
}

// RealLandingGitOps implements LandingGitOps via os/exec git commands.
type RealLandingGitOps struct{}

func (RealLandingGitOps) CurrentBranch(dir string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "symbolic-ref", "--short", "HEAD").CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git symbolic-ref HEAD: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (RealLandingGitOps) ResolveRef(dir, ref string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", ref).CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git rev-parse %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (RealLandingGitOps) UpdateRefTo(dir, ref, sha, oldSHA string) error {
	if ref == "HEAD" {
		return fmt.Errorf("refusing to update HEAD directly; landing must target a concrete ref")
	}
	args := []string{"update-ref", ref, sha}
	if oldSHA != "" {
		args = append(args, oldSHA)
	}
	out, err := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git update-ref %s: %s: %w", ref, strings.TrimSpace(string(out)), err)
	}
	return nil
}

// alwaysSkipSyncPaths lists live-state files governed by bead.Store WithLock.
// The committed worktree version is a stale snapshot of tracker state at claim
// time; the main-worktree copy is always authoritative and must never be
// overwritten by SyncWorkTreeToHead regardless of dirty-before-land state.
var alwaysSkipSyncPaths = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
}

func (RealLandingGitOps) SyncWorkTreeToHead(dir, fromRev string) error {
	return syncWorkTreeToHeadExcludingPaths(dir, fromRev, alwaysSkipSyncPaths)
}

// readTreeHeadWithRetry runs `git read-tree HEAD` in dir, retrying with
// exponential backoff when the git index lock is held by a concurrent process.
//
// Background (ddx-7e659c95): git read-tree needs to acquire .git/index.lock.
// When an operator git command (git status, git commit, etc.) holds the lock
// concurrently, git exits 128 with "Unable to create index.lock: File exists".
// Without retry the main worktree index stays dirty after a merge landing,
// causing a subsequent `git commit beads.jsonl` to sweep in phantom reverts of
// the bead's changes.
//
// The retry budget (30 s, 100 ms → 1 s backoff) matches the
// DefaultLockRetryPolicy used by withTrackerLock so contention handling is
// consistent across all ddx git-index operations.
func readTreeHeadWithRetry(dir string) ([]byte, error) {
	const (
		initialBackoff = 100 * time.Millisecond
		maxBackoff     = 1 * time.Second
		maxElapsed     = 30 * time.Second
	)
	start := time.Now()
	backoff := initialBackoff
	var lastDiag string
	for {
		out, err := internalgit.Command(context.Background(), dir, "read-tree", "HEAD").CombinedOutput()
		if err == nil {
			return out, nil
		}
		// Only retry on index lock contention; all other errors are fatal.
		if !strings.Contains(string(out), "index.lock") {
			return out, err
		}
		// Identify the lock owner and break the lock if it is stale or
		// owned by a dead process. This converts a hard 30s wait into an
		// instant recovery for the common crashed-git case.
		if result, recErr := recoverGitIndexLock(dir); recErr == nil {
			lastDiag = result.Reason
			if result.Removed {
				// Lock cleared — retry immediately.
				continue
			}
		}
		if time.Since(start) >= maxElapsed {
			if lastDiag != "" {
				return out, fmt.Errorf("%s; index-lock owner: %s: %w",
					strings.TrimSpace(string(out)), lastDiag, err)
			}
			return out, err
		}
		time.Sleep(backoff)
		backoff *= 2
		if backoff > maxBackoff {
			backoff = maxBackoff
		}
	}
}

func syncWorkTreeToHeadExcludingPaths(dir, fromRev string, skipPaths []string) error {
	skipWorktreePaths, err := checkpointSkipWorktreePaths(dir)
	if err != nil {
		return err
	}

	// Step 1: sync the index to HEAD. This is required before checkout-index
	// below will do anything useful, and also keeps subsequent CommitTracker
	// calls from building stale trees.
	//
	// ddx-7e659c95: git read-tree requires .git/index.lock. If an operator
	// git command (git status, git commit, etc.) holds the lock concurrently,
	// git read-tree exits 128 with "Unable to create index.lock: File exists".
	// Retry with exponential backoff for up to 30 s so transient operator
	// contention does not leave the main worktree index dirty.
	out, err := readTreeHeadWithRetry(dir)
	if err != nil {
		return fmt.Errorf("git read-tree HEAD: %s: %w", strings.TrimSpace(string(out)), err)
	}
	if err := restoreCheckpointSkipWorktreePaths(dir, skipWorktreePaths); err != nil {
		return err
	}

	// Step 2: compute the list of tracked files changed between the previous
	// HEAD and the current HEAD. These are the files that the landing commit
	// added, modified, or deleted. We only restore THESE files to avoid
	// clobbering unrelated local modifications (agent-logs being written by
	// the running server, beads.jsonl heartbeat updates, operator scratch).
	if fromRev == "" {
		// No previous HEAD known — fall back to the unsafe behaviour of
		// read-tree only. Acceptable when the caller is a best-effort path
		// that cannot reconstruct fromRev.
		return nil
	}
	diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
	if diffErr != nil {
		// Diff failed (bad fromRev, shallow history, etc.) — leave the
		// worktree stale rather than risk a broken checkout. The CommitTracker
		// stale-tree bug is the prior status quo and no worse than before.
		return nil
	}
	changed := strings.Fields(strings.TrimSpace(string(diffOut)))
	if len(changed) == 0 {
		return nil
	}

	// Step 3: split into existing-in-HEAD (checkout-index) and
	// deleted-in-HEAD (os.Remove) buckets. checkout-index only writes files
	// that are in the index; it cannot represent a deletion, so we handle
	// those ourselves.
	skip := map[string]bool{}
	for _, path := range skipPaths {
		skip[filepath.ToSlash(path)] = true
	}
	for _, path := range skipWorktreePaths {
		skip[filepath.ToSlash(path)] = true
	}
	var indexFiles []string
	var removedFiles []string
	for _, f := range changed {
		if skip[filepath.ToSlash(f)] {
			continue
		}
		probe := internalgit.Command(context.Background(), dir, "ls-files", "--error-unmatch", "--", f)
		if probe.Run() == nil {
			indexFiles = append(indexFiles, f)
		} else {
			removedFiles = append(removedFiles, f)
		}
	}

	// Step 4: materialize the index-present files into the working tree.
	// -f overwrites any stale content at these exact paths. Unrelated files
	// are untouched because we pass the specific path list.
	if len(indexFiles) > 0 {
		for _, f := range indexFiles {
			if err := os.MkdirAll(filepath.Dir(filepath.Join(dir, f)), 0o755); err != nil {
				return fmt.Errorf("creating checkout parent for %s: %w", f, err)
			}
		}
		args := []string{"checkout-index", "-f", "--"}
		args = append(args, indexFiles...)
		out2, err2 := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
		if err2 != nil {
			return fmt.Errorf("git checkout-index -f: %s: %w", strings.TrimSpace(string(out2)), err2)
		}
	}

	// Step 5: remove files that the landing commit deleted and whose removal
	// did not propagate to the worktree because update-ref bypassed the
	// working-tree update.
	for _, f := range removedFiles {
		full := filepath.Join(dir, f)
		_ = os.Remove(full) // best-effort; leave the file if removal fails
	}

	return nil
}

func syncWorkTreeToHeadGuarded(gitOps LandingGitOps, dir, fromRev string, dirtyBefore []string, result *LandResult) {
	overlap, err := checkoutSyncDirtyOverlapPaths(dir, fromRev, dirtyBefore)
	if err == nil && len(overlap) > 0 {
		if result != nil {
			result.CheckoutSyncDeferred = true
			result.CheckoutSyncDeferredPaths = appendUniqueStrings(result.CheckoutSyncDeferredPaths, overlap...)
		}
		_ = syncWorkTreeToHeadExcludingPaths(dir, fromRev, overlap)
		return
	}
	_ = gitOps.SyncWorkTreeToHead(dir, fromRev)
}

func ensureLandingWorktreeReady(dir, targetBranch string) error {
	if !isInsideGitWorktree(dir) {
		return nil
	}
	branchOut, err := internalgit.Command(context.Background(), dir, "branch", "--show-current").CombinedOutput()
	if err != nil {
		return fmt.Errorf("checking landing branch: %s: %w", strings.TrimSpace(string(branchOut)), err)
	}
	branch := strings.TrimSpace(string(branchOut))
	if branch == "" {
		return fmt.Errorf("landing worktree is detached; expected branch %q", targetBranch)
	}
	if targetBranch != "" && branch != targetBranch {
		return fmt.Errorf("landing branch mismatch: on %q, want %q", branch, targetBranch)
	}
	return waitForEmptyGitIndex(dir, 2*time.Second)
}

func isInsideGitWorktree(dir string) bool {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--is-inside-work-tree").CombinedOutput()
	return err == nil && strings.TrimSpace(string(out)) == "true"
}

func waitForEmptyGitIndex(dir string, timeout time.Duration) error {
	deadline := time.Now().Add(timeout)
	repairedCorruptIndex := false
	for {
		out, err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").CombinedOutput()
		if err == nil {
			return nil
		}
		// There are staged changes (or a corrupt index). DDx-managed tracker
		// files (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, …) are
		// append-mostly metadata that concurrent workers rewrite continuously;
		// a short wait for them to settle reliably fails on a busy multi-worker
		// host and wedges the queue (ddx-df77e668). They are not code, and the
		// next claim rewrites them anyway, so they must never block a claim.
		// When the only staged paths are tracker files, the landing worktree is
		// clean for claim purposes.
		if blocking, ok := blockingStagedPaths(dir); ok && len(blocking) == 0 {
			return nil
		}
		if !repairedCorruptIndex && isRecoverableLandingIndexCorruption(string(out)) {
			repairedCorruptIndex = true
			if _, recErr := readTreeHeadWithRetry(dir); recErr != nil {
				return fmt.Errorf("repairing landing worktree index: %w", recErr)
			}
			if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
				return nil
			}
		}
		if time.Now().After(deadline) {
			// The index drifted from HEAD. Two causes are possible:
			//   1. A prior land's post-merge SyncWorkTreeToHead failed
			//      (e.g. transient .git/index.lock contention) and its
			//      error was swallowed by the best-effort caller. The
			//      index now matches a recent ancestor of HEAD —
			//      reverting the most recent merges. Recovering by
			//      running read-tree HEAD is safe and unblocks the queue.
			//   2. The operator staged real work that does not match any
			//      ancestor tree. Recovery here would silently destroy
			//      their changes — refuse, surface the error, and let
			//      the operator resolve it.
			if matches, _ := indexMatchesRecentAncestorTree(dir, 20); matches {
				if _, recErr := readTreeHeadWithRetry(dir); recErr == nil {
					if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
						return nil
					}
				}
			}
			stagedOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-status").CombinedOutput()
			staged := strings.TrimSpace(string(stagedOut))
			if staged == "" {
				staged = "unknown staged changes"
			}
			return fmt.Errorf("landing worktree has staged changes after waiting %s:\n%s", timeout, staged)
		}
		time.Sleep(100 * time.Millisecond)
	}
}

func isRecoverableLandingIndexCorruption(output string) bool {
	lower := strings.ToLower(output)
	return strings.Contains(lower, "index file smaller than expected") ||
		strings.Contains(lower, "bad index file") ||
		strings.Contains(lower, "unexpected end of file while reading index")
}

// blockingStagedPaths returns the staged paths that would genuinely block a
// claim — i.e. every staged path that is NOT a DDx-managed tracker/metadata
// file. ok is false when the staged list cannot be read (e.g. a corrupt
// index), so callers can fall through to their corruption-recovery path
// instead of mistaking the read failure for "no blocking changes".
func blockingStagedPaths(dir string) (blocking []string, ok bool) {
	out, err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").CombinedOutput()
	if err != nil {
		return nil, false
	}
	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		p := strings.TrimSpace(line)
		if p == "" || trackerpaths.IsManagedTrackerPath(p) {
			continue
		}
		blocking = append(blocking, p)
	}
	return blocking, true
}

// indexMatchesRecentAncestorTree reports whether the current index's tree
// matches the tree of any of the last `maxDepth` ancestors of HEAD. A
// match means the index reflects a state we have already advanced past —
// the signature of a swallowed SyncWorkTreeToHead failure — and is
// therefore safe to overwrite by re-reading HEAD into the index.
//
// Operator-staged work introduces novel tree contents that will not
// match any historical tree, so the heuristic preserves their work.
func indexMatchesRecentAncestorTree(dir string, maxDepth int) (bool, error) {
	out, err := internalgit.Command(context.Background(), dir, "write-tree").Output()
	if err != nil {
		return false, err
	}
	indexTree := strings.TrimSpace(string(out))
	if indexTree == "" {
		return false, nil
	}
	for depth := 1; depth <= maxDepth; depth++ {
		ref := fmt.Sprintf("HEAD~%d^{tree}", depth)
		treeOut, treeErr := internalgit.Command(context.Background(), dir, "rev-parse", "--verify", ref).Output()
		if treeErr != nil {
			return false, nil
		}
		if strings.TrimSpace(string(treeOut)) == indexTree {
			return true, nil
		}
	}
	return false, nil
}

func checkoutSyncDirtyOverlapPaths(dir, fromRev string, dirtyPaths []string) ([]string, error) {
	if fromRev == "" || len(dirtyPaths) == 0 {
		return nil, nil
	}
	diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
	if diffErr != nil {
		return nil, diffErr
	}
	changed := map[string]bool{}
	for _, path := range strings.Fields(strings.TrimSpace(string(diffOut))) {
		changed[filepath.ToSlash(path)] = true
	}
	if len(changed) == 0 {
		return nil, nil
	}
	var overlap []string
	for _, path := range dirtyPaths {
		slashPath := filepath.ToSlash(path)
		if checkoutSyncDeferralIgnoredPath(slashPath) {
			continue
		}
		if changed[slashPath] {
			overlap = append(overlap, slashPath)
		}
	}
	return overlap, nil
}

func checkoutSyncDeferralIgnoredPath(path string) bool {
	if strings.HasPrefix(path, ".ddx/executions/") ||
		strings.HasPrefix(path, ".ddx/runs/") ||
		strings.HasPrefix(path, ".ddx/backups/") ||
		strings.HasPrefix(path, ".ddx/run-state/") ||
		strings.HasPrefix(path, ".ddx/.git-tracker.lock/") {
		return true
	}
	return path == ".ddx/run-state.json" || path == ExecutionCleanupMetadataFileName
}

func appendUniqueStrings(existing []string, additions ...string) []string {
	seen := make(map[string]bool, len(existing)+len(additions))
	for _, value := range existing {
		seen[value] = true
	}
	for _, value := range additions {
		if seen[value] {
			continue
		}
		seen[value] = true
		existing = append(existing, value)
	}
	return existing
}

func (RealLandingGitOps) AddWorktree(dir, path, rev string) error {
	// --detach so the worktree does not create a persistent branch.
	out, err := internalgit.Command(context.Background(), dir, "worktree", "add", "--force", "--detach", path, rev).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git worktree add %s %s: %s: %w", path, rev, strings.TrimSpace(string(out)), err)
	}
	return nil
}

func (RealLandingGitOps) AddBranchWorktree(dir, path, branch string) error {
	out, err := internalgit.Command(context.Background(), dir, "worktree", "add", "--force", path, branch).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git worktree add %s %s: %s: %w", path, branch, strings.TrimSpace(string(out)), err)
	}
	return nil
}

func (RealLandingGitOps) RemoveWorktree(dir, path string) error {
	_ = internalgit.Command(context.Background(), dir, "worktree", "remove", "--force", path).Run()
	_ = internalgit.Command(context.Background(), dir, "worktree", "prune").Run()
	return nil
}

func (RealLandingGitOps) MergeInto(wtDir, srcRev, msg string) error {
	// --no-ff forces a merge commit even when the merge could fast-forward
	// (which shouldn't happen given our caller's ancestry check, but is a
	// defensive guarantee that target history always gets a marker commit).
	// We inject user.name/user.email via -c so the merge commit can be
	// created even when the worktree inherited no git config; the
	// coordinator is a machine actor and should not adopt a human's identity.
	out, err := internalgit.Command(
		context.Background(), wtDir,
		"-c", "user.name=ddx-land-coordinator",
		"-c", "user.email=coordinator@ddx.local",
		"merge", "--no-ff", "-m", msg, srcRev,
	).CombinedOutput()
	if err != nil {
		_ = internalgit.Command(context.Background(), wtDir, "merge", "--abort").Run()
		return fmt.Errorf("git merge --no-ff %s: %s: %w", srcRev, strings.TrimSpace(string(out)), err)
	}
	return nil
}

func (RealLandingGitOps) HeadRevAt(dir string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "rev-parse", "HEAD").CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git rev-parse HEAD: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return strings.TrimSpace(string(out)), nil
}

func (RealLandingGitOps) CountCommits(dir, base, tip string) int {
	out, err := internalgit.Command(context.Background(), dir, "rev-list", "--count", base+".."+tip).CombinedOutput()
	if err != nil {
		return 0
	}
	s := strings.TrimSpace(string(out))
	n := 0
	for _, c := range s {
		if c >= '0' && c <= '9' {
			n = n*10 + int(c-'0')
		}
	}
	return n
}

func (RealLandingGitOps) StageDir(dir, relPath string) error {
	// Exclude embedded session logs from the evidence commit — tracking
	// multi-thousand-line .jsonl files caused retry review prompts to
	// balloon past 2M tokens and crash every provider with n_keep > n_ctx
	// (ddx-39e27896). manifest.json, result.json, prompt.md, and
	// usage.json remain tracked for audit; the raw session log lives on
	// disk, not in git history.
	args := append([]string{"add", "--force", "--", relPath}, EvidenceLandExcludePathspecs()...)
	out, err := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
	if err != nil {
		return fmt.Errorf("git add %s: %s: %w", relPath, strings.TrimSpace(string(out)), err)
	}
	return nil
}

func (RealLandingGitOps) CommitStaged(dir, msg string) (string, error) {
	out, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
	if len(strings.TrimSpace(string(out))) == 0 {
		return "", nil
	}
	commitOut, err := internalgit.Command(context.Background(), dir,
		"-c", "user.name=ddx-land-coordinator",
		"-c", "user.email=coordinator@ddx.local",
		"commit", "-m", msg,
	).CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("git commit: %s: %w", strings.TrimSpace(string(commitOut)), err)
	}
	shaOut, err := internalgit.Command(context.Background(), dir, "rev-parse", "HEAD").Output()
	if err != nil {
		return "", fmt.Errorf("rev-parse HEAD after evidence commit: %w", err)
	}
	return strings.TrimSpace(string(shaOut)), nil
}

// DiffNumstat implements LandingGitOps.DiffNumstat.
func (RealLandingGitOps) DiffNumstat(dir, base, tip string) (string, error) {
	out, err := internalgit.Command(context.Background(), dir, "diff", "--numstat", base, tip, "--").CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("%s: %w", strings.TrimSpace(string(out)), err)
	}
	return string(out), nil
}

// DiffNameOnly implements LandingGitOps.DiffNameOnly.
func (RealLandingGitOps) DiffNameOnly(dir, base, tip string) ([]string, error) {
	out, err := internalgit.Command(context.Background(), dir, "diff", "--name-only", base, tip, "--").CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("listing changed files: %s: %w", strings.TrimSpace(string(out)), err)
